{% component section %}

{% props {
  label: string.setting({
    label: "Trigger label",
    default: "Details",
  }),
} %}

<div ref="root" class="nazare-disclosure">
  <button ref="trigger" type="button">{{ props.label }}</button>
  <div ref="panel" hidden>
    <slot></slot>
  </div>
</div>

{% stylesheet %}
.nazare-disclosure {
  display: block;
}
.nazare-disclosure--open > [data-nz-ref="panel"] {
  display: block;
}
{% endstylesheet %}

{% script lang="ts" %}
export default island(({ refs }) => {
  refs.trigger.addEventListener("click", () => {
    refs.panel.hidden = !refs.panel.hidden;
    refs.root.classList.toggle("nazare-disclosure--open");
  });
});
{% endscript %}
